/* Sélecteur d'élément : cible tous les <p> */
p {
  color: #374151;
  line-height: 1.6;
}

/* Sélecteur de classe : cible tous les éléments class="titre" */
.titre {
  font-size: 2rem;
  font-weight: bold;
}

/* Sélecteur d'ID : cible l'élément id="hero" (unique) */
#hero {
  background-color: #3b82f6;
  color: white;
}

/* Combinaison : <p> à l'intérieur d'un .article */
.article p {
  margin-bottom: 1rem;
}

/* Pseudo-classe : survol d'un lien */
a:hover {
  text-decoration: underline;
  color: #1d4ed8;
}
